{
    "product_storage.py": "import json\nimport os\nimport logging\n\n# Set up basic logging for the module\nlogging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')\n\nPRODUCTS_FILE = 'data/products.json'\nDATA_DIR = 'data/'\n\ndef _ensure_data_directory_exists():\n    \"\"\"\n    Ensures that the 'data/' directory exists. Creates it if it doesn't.\n    \"\"\"\n    if not os.path.exists(DATA_DIR):\n        os.makedirs(DATA_DIR)\n        logging.info(f\"Created directory: {DATA_DIR}\")\n\ndef load_products() -> list[dict]:\n    \"\"\"\n    Loads all products from the data/products.json file.\n\n    Returns:\n        list[dict]: A list of product dictionaries. Returns an empty list\n                    if the file does not exist, is empty, or contains malformed JSON.\n    \"\"\"\n    _ensure_data_directory_exists()\n    \n    if not os.path.exists(PRODUCTS_FILE):\n        logging.info(f\"Products file not found at {PRODUCTS_FILE}. Returning empty list.\")\n        return []\n\n    try:\n        with open(PRODUCTS_FILE, 'r', encoding='utf-8') as f:\n            content = f.read().strip()\n            if not content:\n                logging.warning(f\"Products file at {PRODUCTS_FILE} is empty. Returning empty list.\")\n                return []\n            \n            products = json.loads(content)\n            if not isinstance(products, list):\n                logging.error(f\"Products file at {PRODUCTS_FILE} contains malformed JSON (not a list). Returning empty list.\")\n                return []\n            return products\n    except FileNotFoundError:\n        # This case is largely covered by os.path.exists, but kept for absolute robustness.\n        logging.error(f\"FileNotFoundError: Products file not found at {PRODUCTS_FILE}.\")\n        return []\n    except json.JSONDecodeError as e:\n        logging.error(f\"json.JSONDecodeError: Error decoding JSON from {PRODUCTS_FILE}: {e}. Returning empty list.\")\n        return []\n    except Exception as e:\n        logging.error(f\"An unexpected error occurred while loading products from {PRODUCTS_FILE}: {e}. Returning empty list.\")\n        return []\n\ndef save_products(products: list[dict]) -> None:\n    \"\"\"\n    Saves a list of products to the data/products.json file.\n\n    Args:\n        products (list[dict]): A list of product dictionaries to be saved.\n\n    Raises:\n        IOError: If there's an issue writing to the file.\n    \"\"\"\n    _ensure_data_directory_exists()\n    try:\n        with open(PRODUCTS_FILE, 'w', encoding='utf-8') as f:\n            json.dump(products, f, indent=4, ensure_ascii=False)\n        logging.info(f\"Successfully saved {len(products)} products to {PRODUCTS_FILE}\")\n    except IOError as e:\n        logging.error(f\"IOError: Could not save products to {PRODUCTS_FILE}: {e}\")\n        raise IOError(f\"Failed to save products due to an I/O error: {e}\")\n    except Exception as e:\n        logging.error(f\"An unexpected error occurred while saving products to {PRODUCTS_FILE}: {e}\")\n        raise IOError(f\"An unexpected error occurred during save operation: {e}\")\n",
    "product_manager.py": "import product_storage\nimport logging\n\n# Set up basic logging for the module\nlogging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')\n\ndef generate_unique_product_id(products: list[dict]) -> int:\n    \"\"\"\n    Generates a unique sequential integer ID for a new product.\n\n    Args:\n        products (list[dict]): The current list of existing product dictionaries.\n\n    Returns:\n        int: A unique sequential integer ID. Returns 1 if the products list is empty.\n    \"\"\"\n    if not products:\n        logging.info(\"Products list is empty, starting ID from 1.\")\n        return 1\n    \n    max_id = 0\n    for product in products:\n        try:\n            # Ensure 'id' exists and is an integer before comparing\n            if 'id' in product and isinstance(product['id'], int):\n                max_id = max(max_id, product['id'])\n            else:\n                logging.warning(f\"Product found without a valid integer 'id' field: {product}\")\n        except TypeError as e:\n            logging.error(f\"Error processing product ID for product: {product}. Error: {e}\")\n\n    new_id = max_id + 1\n    logging.info(f\"Generated new unique product ID: {new_id}\")\n    return new_id\n\ndef add_new_product(name: str, price: float) -> dict:\n    \"\"\"\n    Creates a new product, assigns a unique ID, and persists it to storage.\n\n    Args:\n        name (str): The name of the product.\n        price (float): The price of the product.\n\n    Returns:\n        dict: The newly created product dictionary, including its unique ID.\n\n    Raises:\n        IOError: If there's an issue saving the products to storage.\n    \"\"\"\n    logging.info(f\"Attempting to add new product: Name='{name}', Price={price}\")\n    \n    current_products = product_storage.load_products()\n    \n    new_id = generate_unique_product_id(current_products)\n    \n    new_product = {\n        'id': new_id,\n        'name': name,\n        'price': price\n    }\n    \n    current_products.append(new_product)\n    \n    try:\n        product_storage.save_products(current_products)\n        logging.info(f\"Successfully added and saved new product: {new_product}\")\n        return new_product\n    except IOError as e:\n        logging.error(f\"Failed to add new product due to storage error: {e}\")\n        raise # Re-raise the IOError for main.py to handle more gracefully\n    except Exception as e:\n        logging.error(f\"An unexpected error occurred in add_new_product: {e}\")\n        raise IOError(f\"An unexpected error occurred while adding product: {e}\") # Wrap general exceptions as IOError\n",
    "main.py": "import product_manager\nimport logging\n\n# Set up basic logging for the main application\nlogging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')\n\ndef run_product_creation_flow() -> None:\n    \"\"\"\n    Guides the user through the process of adding a new product.\n    Prompts for product name and price, validates input, and calls the\n    product manager to create and save the product.\n    \"\"\"\n    print(\"\\n--- Add New Product ---\")\n    \n    product_name = \"\"\n    while not product_name:\n        product_name = input(\"Enter Product Name: \").strip()\n        if not product_name:\n            print(\"Product name cannot be empty. Please try again.\")\n    \n    product_price = None\n    while product_price is None:\n        price_input = input(\"Enter Product Price: \").strip()\n        try:\n            price_value = float(price_input)\n            if price_value <= 0:\n                print(\"Product price must be a positive number. Please try again.\")\n            else:\n                product_price = price_value\n        except ValueError:\n            print(\"Invalid price. Please enter a numeric value (e.g., 29.99).\")\n    \n    try:\n        new_product = product_manager.add_new_product(product_name, product_price)\n        print(f\"\\nSUCCESS: Product '{new_product['name']}' added!\")\n        print(f\"Details: ID={new_product['id']}, Price=${new_product['price']:.2f}\")\n    except IOError as e:\n        print(f\"\\nERROR: Could not add product due to a storage issue. Please check logs for details.\")\n        logging.error(f\"Error during product creation flow (IOError): {e}\")\n    except Exception as e:\n        print(f\"\\nERROR: An unexpected error occurred while adding product. Please check logs for details.\")\n        logging.error(f\"Unexpected error during product creation flow: {e}\")\n\ndef display_main_menu() -> None:\n    \"\"\"\n    Displays the main menu options for the product management CLI.\n    \"\"\"\n    print(\"\\n--- Product Management CLI ---\")\n    print(\"1. Add New Product\")\n    print(\"q. Quit\")\n    print(\"------------------------------\")\n\ndef main() -> None:\n    \"\"\"\n    Main function to run the product management CLI application.\n    Enters a loop to display the menu and handle user choices.\n    \"\"\"\n    while True:\n        display_main_menu()\n        choice = input(\"Enter your choice: \").strip().lower()\n        \n        if choice == '1':\n            run_product_creation_flow()\n        elif choice == 'q':\n            print(\"Exiting Product Management CLI. Goodbye!\")\n            break\n        else:\n            print(\"Invalid choice. Please select a valid option from the menu.\")\n\nif __name__ == \"__main__\":\n    main()\n"
}